import * as React from 'react';
import { isDev } from '../utility/is-dev';
import Editable from '../editable/editable';
import { FlowPage, Flow, type StaticFlowItemMeta } from './flow-static';
import { htmlToFlowItems, sanitizeHtml } from './html-flow';

export type HtmlFlowItem = {
  id: string;
  type: string;
  html: string;
  breakBefore: boolean;
};

type FlowDocumentEditable = {
  path: string;
  type?: string;
  [key: string]: unknown;
};

type FlowDocumentProps = {
  /** Rendered HTML to paginate. Convert markdown/Notion to HTML before passing. */
  html: string;
  header?: React.ReactNode;
  footer?: React.ReactNode;
  className?: string;
  style?: React.CSSProperties;
  flowAreaClassName?: string;
  flowAreaStyle?: React.CSSProperties;
  /** Stable flow id within the page. Defaults to "flow-document". */
  id?: string;
  idPrefix?: string;
  flowClassName?: string;
  itemClassName?: string | ((item: HtmlFlowItem, index: number) => string | undefined);
  /** Per-tag break metadata. Merged over the built-in defaults (shallow, by tag). */
  metaDefaults?: Partial<Record<string, StaticFlowItemMeta>>;
  getItemMeta?: (item: HtmlFlowItem, index: number) => StaticFlowItemMeta | undefined;
  /** Override the default sanitized-HTML renderer (e.g. to map HTML to React). */
  renderItem?: (item: HtmlFlowItem, index: number) => React.ReactNode;
  /**
   * HTML sanitizer applied by the default renderer. Defaults to the built-in
   * best-effort sanitizer. Pass DOMPurify.sanitize for stronger guarantees, or
   * `false` to opt out for trusted HTML (dev-warns once).
   */
  sanitize?: ((html: string) => string) | false;
  /** When set, wraps the flow body in <Editable dialog={editable}> for click-to-edit. */
  editable?: FlowDocumentEditable;
  /** Injectable parser (SSR/tests). Defaults to the DOM-based parser. */
  parseHtml?: (html: string) => unknown[];
};

// Block-level break defaults keyed by tag name. Headings stay with the block
// that follows them; container elements try to move as a whole.
const DEFAULT_META_DEFAULTS: Record<string, StaticFlowItemMeta> = {
  h1: { keepWithNext: 1 },
  h2: { keepWithNext: 1 },
  h3: { keepWithNext: 1 },
  h4: { keepWithNext: 1 },
  h5: { keepWithNext: 1 },
  h6: { keepWithNext: 1 },
  table: { avoidBreakInside: true },
  ul: { avoidBreakInside: true },
  ol: { avoidBreakInside: true },
  pre: { avoidBreakInside: true },
  blockquote: { avoidBreakInside: true },
  figure: { avoidBreakInside: true },
  img: { avoidBreakInside: true },
};

let warnedSanitizeDisabled = false;

function useSanitizer(sanitize: FlowDocumentProps['sanitize']): (html: string) => string {
  return React.useMemo(() => {
    if (sanitize === false) {
      if (isDev() && !warnedSanitizeDisabled) {
        warnedSanitizeDisabled = true;
        console.warn(
          '[uhuu-components] Static.FlowDocument sanitize is disabled. ' +
          'Only pass sanitize={false} for trusted HTML.'
        );
      }
      return (html: string) => html;
    }

    return typeof sanitize === 'function' ? sanitize : sanitizeHtml;
  }, [sanitize]);
}

/**
 * Batteries-included flow page for an HTML body.
 *
 * Splits `html` into block-level Static.Flow items, applies sensible break
 * metadata, and renders them inside a height-constrained FlowPage so PageEditor
 * can create render-only continuation pages. The page chrome (header/footer),
 * the optional Editable wrapper, pagination, numbering, and print filtering all
 * stay React-driven — only the variable body is injected as HTML.
 */
export function FlowDocument({
  html,
  header,
  footer,
  className = '',
  style,
  flowAreaClassName = '',
  flowAreaStyle,
  id = 'flow-document',
  idPrefix,
  flowClassName = 'w-full',
  itemClassName,
  metaDefaults,
  getItemMeta,
  renderItem,
  sanitize,
  editable,
  parseHtml,
}: FlowDocumentProps) {
  const items = React.useMemo(
    () => htmlToFlowItems(html, { idPrefix, parseHtml }) as HtmlFlowItem[],
    [html, idPrefix, parseHtml]
  );

  const mergedMetaDefaults = React.useMemo(
    () => ({ ...DEFAULT_META_DEFAULTS, ...(metaDefaults ?? {}) }),
    [metaDefaults]
  );

  const sanitizer = useSanitizer(sanitize);

  const resolveItemMeta = React.useCallback(
    (item: HtmlFlowItem, index: number): StaticFlowItemMeta => ({
      breakBefore: item.breakBefore,
      ...(getItemMeta?.(item, index) ?? {}),
    }),
    [getItemMeta]
  );

  const resolveRenderItem = React.useCallback(
    (item: HtmlFlowItem, index: number): React.ReactNode => {
      if (renderItem) return renderItem(item, index);
      return (
        <div
          className="uhuu-flow-html-block"
          dangerouslySetInnerHTML={{ __html: sanitizer(item.html) }}
        />
      );
    },
    [renderItem, sanitizer]
  );

  const flow = (
    <Flow
      id={id}
      items={items}
      getKey={(item) => item.id}
      className={flowClassName}
      itemClassName={itemClassName}
      metaDefaults={mergedMetaDefaults}
      getItemMeta={resolveItemMeta}
      renderItem={resolveRenderItem}
    />
  );

  return (
    <FlowPage
      className={className}
      style={style}
      flowAreaClassName={flowAreaClassName}
      flowAreaStyle={flowAreaStyle}
      header={header}
      footer={footer}
    >
      {editable ? <Editable dialog={editable}>{flow}</Editable> : flow}
    </FlowPage>
  );
}

export default FlowDocument;
