import { useState, useRef, useEffect } from 'react';
import { ChevronDown, ArrowUp, ArrowDown, Plus, Copy, Trash2, Pencil } from 'lucide-react';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '../../ui/dropdown-menu';

export interface PageNameDropdownProps {
  name: string;
  canRename?: boolean;
  canMoveUp?: boolean;
  canMoveDown?: boolean;
  canAddPage?: boolean;
  canDuplicate?: boolean;
  canDelete?: boolean;
  onRename?: (name: string) => void;
  onMoveUp?: () => void;
  onMoveDown?: () => void;
  onAddPage?: () => void;
  onDuplicate?: () => void;
  onDelete?: () => void;
}

export function PageNameDropdown({
  name,
  canRename,
  canMoveUp,
  canMoveDown,
  canAddPage,
  canDuplicate,
  canDelete,
  onRename,
  onMoveUp,
  onMoveDown,
  onAddPage,
  onDuplicate,
  onDelete,
}: PageNameDropdownProps) {
  const [open, setOpen] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [renameValue, setRenameValue] = useState(name);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    setRenameValue(name);
  }, [name]);

  useEffect(() => {
    if (isEditing) {
      setTimeout(() => {
        inputRef.current?.focus();
        inputRef.current?.select();
      }, 10);
    }
  }, [isEditing]);

  const commitRename = () => {
    const trimmed = renameValue.trim();
    if (trimmed && trimmed !== name) onRename?.(trimmed);
    setIsEditing(false);
  };

  const hasActions = canMoveUp || canMoveDown || canAddPage || canDuplicate || canDelete;
  const hasAnyContent = canRename || hasActions;

  if (isEditing) {
    return (
      <input
        ref={inputRef}
        value={renameValue}
        onChange={(e) => setRenameValue(e.target.value)}
        onKeyDown={(e) => {
          if (e.key === 'Enter') commitRename();
          if (e.key === 'Escape') { setRenameValue(name); setIsEditing(false); }
          e.stopPropagation();
        }}
        onBlur={commitRename}
        className="text-xs font-medium text-gray-800 bg-white border border-blue-400 rounded-md px-2 py-1 focus:outline-none focus:ring-2 focus:ring-blue-400/30 max-w-[140px] h-7"
        data-uhuu-editor
      />
    );
  }

  if (!hasAnyContent) {
    return (
      <span className="text-xs font-medium text-gray-600 truncate max-w-[120px]">
        {name}
      </span>
    );
  }

  return (
    <DropdownMenu open={open} onOpenChange={setOpen} modal={false}>
      <DropdownMenuTrigger asChild>
        <button
          className="flex items-center gap-1 text-xs font-medium text-gray-700 hover:text-gray-900 rounded-md px-2 h-7 hover:bg-gray-100 transition-colors border border-transparent hover:border-gray-200"
          data-uhuu-editor
        >
          <span className="truncate max-w-[120px]">{name}</span>
          <ChevronDown className="w-3.5 h-3.5 text-gray-500 shrink-0" />
        </button>
      </DropdownMenuTrigger>
      <DropdownMenuContent className="min-w-44 p-1" align="start">
        {canRename && (
          <DropdownMenuItem onSelect={(e) => { e.preventDefault(); setOpen(false); setIsEditing(true); }}>
            <Pencil className="w-3.5 h-3.5 mr-2" />
            Rename
          </DropdownMenuItem>
        )}
        {canRename && hasActions && <DropdownMenuSeparator />}
        {canMoveUp && (
          <DropdownMenuItem onClick={onMoveUp}>
            <ArrowUp className="w-3.5 h-3.5 mr-2" />
            Move up
          </DropdownMenuItem>
        )}
        {canMoveDown && (
          <DropdownMenuItem onClick={onMoveDown}>
            <ArrowDown className="w-3.5 h-3.5 mr-2" />
            Move down
          </DropdownMenuItem>
        )}
        {canAddPage && (canMoveUp || canMoveDown) && <DropdownMenuSeparator />}
        {canAddPage && (
          <DropdownMenuItem onClick={onAddPage}>
            <Plus className="w-3.5 h-3.5 mr-2" />
            Add page
          </DropdownMenuItem>
        )}
        {canDuplicate && (
          <DropdownMenuItem onClick={onDuplicate}>
            <Copy className="w-3.5 h-3.5 mr-2" />
            Duplicate
          </DropdownMenuItem>
        )}
        {canDelete && <DropdownMenuSeparator />}
        {canDelete && (
          <DropdownMenuItem onClick={onDelete} className="text-red-600 focus:text-red-700 focus:bg-red-50">
            <Trash2 className="w-3.5 h-3.5 mr-2" />
            Delete
          </DropdownMenuItem>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}
