import { useMemo, useCallback } from 'react';
import { PageItem, InsertPosition } from './page-group-utils';
import { AvailableItem } from './use-page-groups';

export interface PageItemActionHandlers {
  onAddPage?: () => void;
  onMoveUp?: () => void;
  onMoveDown?: () => void;
  onDuplicate?: () => void;
}

interface UsePageItemActionsOptions {
  items: PageItem[];
  reorderItems: (newOrder: PageItem[]) => void;
  availableItemsToAdd: AvailableItem[];
  setPendingInsertPosition: (pos: InsertPosition) => void;
  openAddDialog: () => void;
}

/**
 * Returns a stable `buildHandlers` factory that computes per-item action handlers
 * (move up, move down, duplicate, add page). Call once at component level; invoke
 * the returned factory per item inside render loops — no hook rules violated.
 *
 * middleItems (items without strictPosition) is computed once via useMemo so the
 * factory is O(1) per item after the initial filter.
 */
export function usePageItemActions({
  items,
  reorderItems,
  availableItemsToAdd,
  setPendingInsertPosition,
  openAddDialog,
}: UsePageItemActionsOptions) {
  const middleItems = useMemo(
    () => items.filter(i => !(i as any).strictPosition),
    [items]
  );

  const buildHandlers = useCallback(
    (topItem: PageItem | undefined, anchorId: string | null): PageItemActionHandlers => {
      if (!topItem) return {};

      const topId = topItem.id;
      const topMiddleIndex = middleItems.findIndex(i => i.id === topId);
      const isMiddle = topMiddleIndex !== -1;

      const onMoveUp = isMiddle && topMiddleIndex > 0 ? () => {
        const next = [...items];
        const i = next.findIndex(x => x.id === topId);
        if (i < 1) return;
        [next[i - 1], next[i]] = [next[i], next[i - 1]];
        reorderItems(next);
      } : undefined;

      const onMoveDown = isMiddle && topMiddleIndex < middleItems.length - 1 ? () => {
        const next = [...items];
        const i = next.findIndex(x => x.id === topId);
        if (i < 0 || i >= next.length - 1) return;
        [next[i], next[i + 1]] = [next[i + 1], next[i]];
        reorderItems(next);
      } : undefined;

      const onDuplicate = isMiddle && !!(topItem as any).repeatable ? () => {
        const source = (items.find(x => x.id === topId) ?? topItem) as PageItem;
        const clone = { ...source, id: `${topId}_copy_${Date.now()}` } as PageItem;
        const next = [...items];
        const i = next.findIndex(x => x.id === topId);
        next.splice(i < 0 ? next.length : i + 1, 0, clone);
        reorderItems(next);
      } : undefined;

      const onAddPage = anchorId && availableItemsToAdd.length > 0 ? () => {
        setPendingInsertPosition({ mode: 'before', anchorId });
        openAddDialog();
      } : undefined;

      return { onAddPage, onMoveUp, onMoveDown, onDuplicate };
    },
    [items, middleItems, reorderItems, availableItemsToAdd, setPendingInsertPosition, openAddDialog]
  );

  return buildHandlers;
}
