import { useContext } from "react";
import { ConfigContext } from '../config/config-provider'; // Import the ConfigContext
import { getDialogProps } from '../editable/dialog-props';
import { cn } from '../ui/cn';
import { useImageLoadFailure } from './use-image-load-failure';
import './image.css';

interface ImageSpreadProps {  
  src?: string;
  onError?: React.ReactEventHandler<HTMLImageElement>;
  imageClassName?: string;
  side?: "start" | "end";
  backgroundColor?: string;
  width?: number;
  left?: number;
  right?: number;
  top?: number;
  bottom?: number;
  height?: number;
  pageWidth?: number;
  pageHeight?: number;
  bleed?: number;
  dialog?: object;
  children?: React.ReactNode;
  dataUhuu?: any;
}

// Constants
export default function ImageSpread(props: ImageSpreadProps) {

  const config = useContext(ConfigContext);
  const imageLoadErrorHandler = useImageLoadFailure({
    onError: props.onError,
  });
  // Get page dimensions and bleed from props or use defaults (from context if not provided)
  const BLEED = props.bleed ?? config?.page?.bleed ?? 0;  
  const PAGE_CONTENT_WIDTH = (props.pageWidth ?? config?.page?.width ?? 210);
  const PAGE_CONTENT_HEIGHT = (props.pageHeight ?? config?.page?.height ?? 297);
  
  const {
    src,
    imageClassName,
    side,
    backgroundColor,
    width: imageW,
    height: imageH,
    left: imageL = 0,
    right: imageR = 0,
    top: imageT = 0,
    bottom: imageB = 0,        
  } = props;

  const unitFormat = (val: number): string => {
    return `${val}mm`;
  };

  const calculateImageWidth = (): number => {
    let result = imageW; 
    if(!imageW) {
      result = 2 * PAGE_CONTENT_WIDTH;
      if(!imageL) result += 2 * BLEED;
      if(!imageR) result += 2 * BLEED;
      if(imageL || imageR) result -= (imageL ?? 0) + (imageR ?? 0);
    }
    else {
      if(!imageL && !imageR) result += BLEED;
    }
    return result;
  };

  const calculateImageHeight = (): number => {
    let result = imageH; 
    if(!imageH) {
      result = PAGE_CONTENT_HEIGHT;
      // Add top bleed if top is 0 (will be positioned with top: -BLEED)
      if(!imageT) result += BLEED;
      // Add bottom bleed if bottom is 0 (will be positioned with bottom: -BLEED)
      // When using bottom positioning, we add bleed to height so element extends below
      if(!imageB) result += BLEED;
      if(imageT || imageB) result -= (imageT ?? 0) + (imageB ?? 0);
    }
    else {
      if(!imageT && !imageB) result += BLEED;
    }
    return result;
  };

  // Calculate dimensions
  const imageWidth = calculateImageWidth();
  const imageHeight = calculateImageHeight();

  const formatStyleValue = (value: number | undefined): string | undefined => 
    value !== undefined ? unitFormat(value) : undefined;

  const createStyle = (styles: Record<string, string | undefined>) => {
    return Object.fromEntries(
      Object.entries(styles).filter(([_, value]) => value !== undefined)
    );
  };

  // Calculate positioning values
  // Note: We only use 'left' in CSS; width calculation handles right side
  const imageLeft = imageL > 0 ? imageL + BLEED : 0;
  const imageRight = imageR > 0 ? imageR + BLEED : 0; // Calculated but not used in CSS (width handles it)
  const imageTop = imageT > 0 ? imageT + BLEED : 0;
  // Bottom: when imageB is 0, use -BLEED to extend into bleed area (matching top behavior)
  const imageBottom = imageB > 0 ? imageB + BLEED : 0;
  const rightPageOffset = -1 * PAGE_CONTENT_WIDTH + imageLeft; // Offset of right page
  
  // Only set explicit height when BOTH top and bottom have explicit values (both > 0)
  // Otherwise, let CSS calculate height from top and bottom positioning
  // This avoids conflicts when one side uses bleed positioning (-BLEED)
  const useExplicitHeight = imageT > 0 && imageB > 0;
  
  const leftStyle = createStyle({
    backgroundColor,
    width: formatStyleValue(imageWidth),
    ...(useExplicitHeight ? { height: formatStyleValue(imageHeight) } : {}),
    left: formatStyleValue(imageLeft),
    top: formatStyleValue(imageTop),
    bottom: formatStyleValue(imageBottom)
  });

  const rightStyle = createStyle({
    width: formatStyleValue(imageWidth),
    ...(useExplicitHeight ? { height: formatStyleValue(imageHeight) } : {}),
    left: formatStyleValue(rightPageOffset),
    top: formatStyleValue(imageTop),
    bottom: formatStyleValue(imageBottom)
  });

  return <div className={`uhuu-image-container`} style={side == "end" ? rightStyle : leftStyle} {...(props.dataUhuu !== undefined ? { 'data-uhuu': props.dataUhuu } : {})}>
        <div className="uhuu-image-inner" {...getDialogProps(props, config)}>
          <img
            className={cn("cover-image object-cover object-center", imageClassName)}
            src={src || null}
            onError={imageLoadErrorHandler}
          />
          {props.children}
        </div>
      </div>
}
