export const getDialogProps = (props, config) => {
    const dialog = props.dialog;

    if (!dialog) return {};

    const isRendererMode = typeof window !== 'undefined' && window.$uhuu_renderer;
    
    if(config?.page?.paginationType === 'dynamic') return {
      'data-uhuu': JSON.stringify(dialog)
    };

    if (isRendererMode) return {
      'data-uhuu' : ''
    };

    return {
      onClick: (e) => {
        if (typeof window !== 'undefined' && window.$uhuu_renderer) return;
        e.stopPropagation();
        window.$uhuu?.editDialog(dialog);
      },
      'data-uhuu' : ''
    };
  };
