import * as React from 'react';
import Pagination from '../../pagination-static/pagination-static';
import Sheet from '../../pagination-static/sheet-static';
import {
  StaticFlowContext,
  type StaticFlowChunk,
  type StaticFlowMeasurement,
} from '../../pagination-static/flow-static';
import type { PageComponent, PageGroup, PageItem, StandalonePage } from './page-group-utils';
import type { PageDataBinding } from './data-binding';

interface PageCanvasProps {
  pageId: string;
  templateId?: string;
  componentKey?: string;
  component?: PageComponent;
  payload?: any;
  pagePayload?: any;
  integration?: any;
  page?: StandalonePage;
  parentGroup?: PageItem;
  setup?: { width: number; height: number; [key: string]: any };
  reference?: React.ReactNode;
  overlay?: React.ReactNode | ((args: { pageNo: number; pageId: string }) => React.ReactNode);
  className?: string;
  pageNo?: number;
  totalPages?: number;
  measurementPageNo?: number;
  measurementTotalPages?: number;
  dataBinding?: PageDataBinding;
  flowPageIndex?: number;
  flowChunksByFlowId?: Record<string, StaticFlowChunk[]>;
  measureFlow?: boolean;
  flowMeasurementKey?: string;
  flowMeasurementVersion?: string;
  onFlowMeasurement?: (pageKey: string, measurement: StaticFlowMeasurement) => void;
  renderVisible?: boolean;
}

/**
 * Small helper that renders a single page with Pagination + Sheet
 * and optional reference/overlay. Keeps templates from duplicating
 * the same scaffold for every page render.
 */
export function PageCanvas({
  pageId,
  templateId,
  componentKey,
  component: PageComponent,
  payload,
  pagePayload,
  integration,
  page,
  parentGroup,
  setup,
  reference,
  overlay,
  className,
  pageNo = 0,
  totalPages,
  measurementPageNo,
  measurementTotalPages,
  dataBinding,
  flowPageIndex = 0,
  flowChunksByFlowId,
  measureFlow = false,
  flowMeasurementKey,
  flowMeasurementVersion,
  onFlowMeasurement,
  renderVisible = true,
}: PageCanvasProps) {
  const renderOverlay = typeof overlay === 'function'
    ? (pageNo: number) => overlay({ pageNo, pageId })
    : () => overlay;

  // Build automatic class for page key targeting
  const pageKey = componentKey || templateId || pageId;
  const pageKeyClass = pageKey ? `uhuu-page--${pageKey}` : '';
  const combinedClassName = [pageKeyClass, className].filter(Boolean).join(' ');

  const renderComponent = (
    componentPageNo: number = pageNo,
    componentTotalPages: number | undefined = totalPages
  ) => PageComponent ? (
    <PageComponent
      payload={payload}
      pagePayload={pagePayload}
      integration={integration}
      pageId={pageId}
      templateId={templateId ?? componentKey ?? pageId}
      pageNum={componentPageNo}
      totalPages={componentTotalPages}
      page={page}
      parentGroup={parentGroup as PageGroup}
      componentKey={componentKey}
      dataBinding={dataBinding}
    />
  ) : null;

  const visibleFlowContext = React.useMemo(
    () => ({
      mode: 'visible' as const,
      pageIndex: flowPageIndex,
      chunksByFlowId: flowChunksByFlowId,
    }),
    [flowPageIndex, flowChunksByFlowId]
  );

  const registerFlowMeasurement = React.useCallback((measurement: StaticFlowMeasurement) => {
    if (!flowMeasurementKey) return;
    onFlowMeasurement?.(flowMeasurementKey, measurement);
  }, [flowMeasurementKey, onFlowMeasurement]);

  const measureFlowContext = React.useMemo(
    () => ({
      mode: 'measure' as const,
      pageIndex: 0,
      measurementVersion: flowMeasurementVersion,
      registerMeasurement: registerFlowMeasurement,
    }),
    [flowMeasurementVersion, registerFlowMeasurement]
  );

  return (
    <>
      {measureFlow && onFlowMeasurement && flowMeasurementKey && (
        <div
          style={{
            position: 'fixed',
            visibility: 'hidden',
            pointerEvents: 'none',
            left: '-100000px',
            top: 0,
            width: 0,
            height: 0,
            overflow: 'hidden',
            zIndex: -1,
          }}
          aria-hidden="true"
          data-uhuu-flow-measurement="true"
        >
          <Pagination setup={setup}>
            <Sheet className={combinedClassName} pageNo={pageNo} data-page-key={pageKey}>
              <StaticFlowContext.Provider value={measureFlowContext}>
                {renderComponent(
                  measurementPageNo ?? pageNo,
                  measurementTotalPages ?? totalPages
                )}
              </StaticFlowContext.Provider>
            </Sheet>
          </Pagination>
        </div>
      )}

      {renderVisible && (
        <Pagination setup={setup}>
          <Sheet
            className={combinedClassName}
            pageNo={pageNo}
            overlay={({ pageNo }) => renderOverlay(pageNo)}
            data-page-key={pageKey}
          >
            {reference}
            <StaticFlowContext.Provider value={visibleFlowContext}>
              {renderComponent(pageNo, totalPages)}
            </StaticFlowContext.Provider>
          </Sheet>
        </Pagination>
      )}
    </>
  );
}

export default PageCanvas;
